```typescript name=frontend/src/services/api.ts
import axios, { AxiosInstance, AxiosError } from 'axios';
import { jwtDecode } from 'jwt-decode';

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5000/api';

class ApiService {
  private api: AxiosInstance;
  private token: string | null = localStorage.getItem('token');

  constructor() {
    this.api = axios.create({
      baseURL: API_BASE_URL,
      headers: {
        'Content-Type': 'application/json',
      },
    });

    // Add token to requests
    this.api.interceptors.request.use((config) => {
      const token = localStorage.getItem('token');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      return config;
    });

    // Handle errors
    this.api.interceptors.response.use(
      (response) => response,
      (error: AxiosError) => {
        if (error.response?.status === 401) {
          localStorage.removeItem('token');
          window.location.href = '/login';
        }
        return Promise.reject(error);
      }
    );
  }

  // Auth endpoints
  async register(username: string, email: string, password: string, age: number) {
    const response = await this.api.post('/auth/register', {
      username,
      email,
      password,
      age,
    });
    return response.data;
  }

  async login(username: string, password: string) {
    const response = await this.api.post('/auth/login', {
      username,
      password,
    });
    if (response.data.access_token) {
      localStorage.setItem('token', response.data.access_token);
    }
    return response.data;
  }

  async getProfile() {
    const response = await this.api.get('/auth/profile');
    return response.data;
  }

  async updateProfile(data: any) {
    const response = await this.api.put('/auth/profile', data);
    return response.data;
  }

  // Game endpoints
  async getActivities(level?: number) {
    const params = level ? { level } : {};
    const response = await this.api.get('/game/activities', { params });
    return response.data;
  }

  async getActivity(activityId: number) {
    const response = await this.api.get(`/game/activity/${activityId}`);
    return response.data;
  }

  async submitActivity(activityId: number, responses: any, timeSpent: number) {
    const response = await this.api.post('/game/submit-response', {
      activity_id: activityId,
      responses,
      time_spent: timeSpent,
    });
    return response.data;
  }

  async getLeaderboard(limit: number = 100, ageGroup?: string) {
    const params = { limit, ...(ageGroup && { age_group: ageGroup }) };
    const response = await this.api.get('/game/leaderboard', { params });
    return response.data;
  }

  // Analytics endpoints
  async getDashboard() {
    const response = await this.api.get('/analytics/dashboard');
    return response.data;
  }

  async getProgressByLevel() {
    const response = await this.api.get('/analytics/progress-by-level');
    return response.data;
  }

  async getActivityHistory(limit: number = 50, level?: number) {
    const params = { limit, ...(level && { level }) };
    const response = await this.api.get('/analytics/activity-history', { params });
    return response.data;
  }

  async getBadges() {
    const response = await this.api.get('/analytics/badges');
    return response.data;
  }

  async getInsights() {
    const response = await this.api.get('/analytics/insights');
    return response.data;
  }

  async getCertificate() {
    const response = await this.api.get('/analytics/certificate');
    return response.data;
  }

  async getRecommendations() {
    const response = await this.api.get('/analytics/recommendations');
    return response.data;
  }
}

export default new ApiService();
