import { create } from 'zustand';
import { AuthState, User } from '../types';
import api from '../services/api';

interface AuthStore extends AuthState {
  login: (username: string, password: string) => Promise<void>;
  register: (username: string, email: string, password: string, age: number) => Promise<void>;
  logout: () => void;
  refreshProfile: () => Promise<void>;
}

export const useAuthStore = create<AuthStore>((set) => ({
  token: localStorage.getItem('token'),
  user: null,
  isAuthenticated: !!localStorage.getItem('token'),

  login: async (username: string, password: string) => {
    try {
      const response = await api.login(username, password);
      set({
        token: response.access_token,
        user: response.user,
        isAuthenticated: true,
      });
    } catch (error) {
      throw error;
    }
  },

  register: async (username: string, email: string, password: string, age: number) => {
    try {
      const response = await api.register(username, email, password, age);
      set({
        user: response.user,
      });
    } catch (error) {
      throw error;
    }
  },

  logout: () => {
    localStorage.removeItem('token');
    set({
      token: null,
      user: null,
      isAuthenticated: false,
    });
  },

  refreshProfile: async () => {
    try {
      const response = await api.getProfile();
      set({
        user: response.user,
      });
    } catch (error) {
      console.error('Failed to refresh profile', error);
    }
  },
}));
