```yaml name=docker/docker-compose.yml
version: '3.8'

services:
  postgres:
    image: postgres:15-alpine
    environment:
      POSTGRES_USER: ${DB_USER:-lsq_user}
      POSTGRES_PASSWORD: ${DB_PASSWORD:-lsq_password}
      POSTGRES_DB: ${DB_NAME:-life_skills_quest}
    ports:
      - "5432:5432"
    volumes:
      - postgres_data:/var/lib/postgresql/data
    networks:
      - lsq-network

  redis:
    image: redis:7-alpine
    ports:
      - "6379:6379"
    networks:
      - lsq-network

  backend:
    build:
      context: .
      dockerfile: docker/Dockerfile.backend
    environment:
      DATABASE_URL: postgresql://${DB_USER:-lsq_user}:${DB_PASSWORD:-lsq_password}@postgres:5432/${DB_NAME:-life_skills_quest}
      FLASK_ENV: ${FLASK_ENV:-production}
      JWT_SECRET_KEY: ${JWT_SECRET_KEY:-change-me-in-production}
    ports:
      - "5000:5000"
    depends_on:
      - postgres
      - redis
    networks:
      - lsq-network
    command: >
      sh -c "flask db upgrade &&
             gunicorn --bind 0.0.0.0:5000 --workers 4 app:create_app()"

  frontend:
    build:
      context: .
      dockerfile: docker/Dockerfile.frontend
    environment:
      VITE_API_URL: ${API_URL:-http://localhost:5000/api}
    ports:
      - "3000:3000"
    depends_on:
      - backend
    networks:
      - lsq-network

  nginx:
    image: nginx:alpine
    ports:
      - "80:80"
      - "443:443"
    volumes:
      - ./docker/nginx.conf:/etc/nginx/nginx.conf:ro
    depends_on:
      - backend
      - frontend
    networks:
      - lsq-network

volumes:
  postgres_data:

networks:
  lsq-network:
    driver: bridge
```

```nginx name=docker/nginx.conf
events {
    worker_connections 1024;
}

http {
    upstream backend {
        server backend:5000;
    }

    upstream frontend {
        server frontend:3000;
    }

    server {
        listen 80;
        server_name localhost;

        # Frontend
        location / {
            proxy_pass http://frontend;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
        }

        # API
        location /api/ {
            proxy_pass http://backend;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
        }

        # Health check
        location /health {
            proxy_pass http://backend;
        }
    }
}
