    // Reset store state
    useAuthStore.setState({
      token: null,
      user: null,
      isAuthenticated: false,
    });
    jest.clearAllMocks();
  });

  test('login updates store correctly', async () => {
    mockedApi.login.mockResolvedValue({
      access_token: 'test_token',
      user: { id: 1, username: 'testuser' },
    });

    const { login } = useAuthStore.getState();
    await login('testuser', 'password');

    const state = useAuthStore.getState();
    expect(state.token).toBe('test_token');
    expect(state.isAuthenticated).toBe(true);
    expect(state.user?.username).toBe('testuser');
  });

  test('logout clears store', () => {
    useAuthStore.setState({
      token: 'test_token',
      user: { id: 1, username: 'test' },
      isAuthenticated: true,
    });

    const { logout } = useAuthStore.getState();
    logout();

    const state = useAuthStore.getState();
    expect(state.token).toBeNull();
    expect(state.isAuthenticated).toBe(false);
  });

  test('register updates user', async () => {
    mockedApi.register.mockResolvedValue({
      message: 'Success',
      user: { id: 1, username: 'newuser' },
    });

    const { register } = useAuthStore.getState();
    await register('newuser', 'new@example.com', 'password', 15);

    const state = useAuthStore.getState();
    expect(state.user?.username).toBe('newuser');
  });

  test('refreshProfile updates user data', async () => {
