"""
Skill Radar Chart using D3.js
Visualizes proficiency across all 5 skill dimensions
"""

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface SkillRadarChartProps {
  data: {
    xp_by_level: {
      self_awareness: number;
      communication: number;
      decision_making: number;
      creativity: number;
      wellness: number;
    };
  };
}

export default function SkillRadarChart({ data }: SkillRadarChartProps) {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const skillData = [
      { skill: 'Self-Awareness', value: data.xp_by_level.self_awareness, max: 200 },
      { skill: 'Communication', value: data.xp_by_level.communication, max: 200 },
      { skill: 'Decision-Making', value: data.xp_by_level.decision_making, max: 200 },
      { skill: 'Creativity', value: data.xp_by_level.creativity, max: 200 },
      { skill: 'Wellness', value: data.xp_by_level.wellness, max: 200 },
    ];

    const width = 500;
    const height = 500;
    const margin = 60;
    const radius = Math.min(width, height) / 2 - margin;
    const numAxes = skillData.length;
    const angleSlice = (Math.PI * 2) / numAxes;

    // Clear previous
    d3.select(svgRef.current).selectAll("*").remove();

    const svg = d3
      .select(svgRef.current)
      .attr('width', width)
      .attr('height', height)
      .style('background', 'transparent');

    const g = svg
      .append('g')
      .attr('transform', `translate(${width / 2}, ${height / 2})`);

    // Draw concentric circles (grid)
    const levels = 4;
    for (let i = levels; i > 0; i--) {
      const levelRadius = (radius / levels) * i;

      g.append('circle')
        .attr('r', levelRadius)
        .style('fill', 'none')
        .style('stroke', '#64748b')
        .style('stroke-width', 0.5)
        .style('opacity', 0.3);

      // Add level labels
      g.append('text')
        .attr('x', 5)
        .attr('y', -levelRadius)
        .text(`${(i / levels) * 100}%`)
        .style('font-size', '10px')
        .style('fill', '#a1a5b4')
        .style('text-anchor', 'start');
    }

    // Draw axes and labels
    skillData.forEach((d, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const x = radius * Math.cos(angle);
      const y = radius * Math.sin(angle);

      // Draw axis line
      g.append('line')
        .attr('x1', 0)
        .attr('y1', 0)
        .attr('x2', x)
        .attr('y2', y)
        .style('stroke', '#94a3b8')
        .style('stroke-width', 1)
        .style('opacity', 0.2);

      // Add skill labels
      const labelRadius = radius * 1.15;
      const labelX = labelRadius * Math.cos(angle);
      const labelY = labelRadius * Math.sin(angle);

      g.append('text')
        .attr('x', labelX)
        .attr('y', labelY)
        .text(d.skill)
        .style('font-size', '12px')
        .style('fill', '#e2e8f0')
        .style('font-weight', '600')
        .style('text-anchor', 'middle')
        .style('dominant-baseline', 'middle');
    });

    // Draw data points and polygon
    const points = skillData.map((d, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const value = d.value / d.max;
      const x = radius * value * Math.cos(angle);
      const y = radius * value * Math.sin(angle);
      return [x, y];
    });

    const lineGenerator = d3.line();
    const pathData = lineGenerator(points as any) + 'Z';

    // Fill polygon
    g.append('path')
      .attr('d', pathData)
      .style('fill', '#a78bfa')
      .style('opacity', 0.25)
      .style('stroke', '#a78bfa')
      .style('stroke-width', 2);

    // Draw data points
    g.selectAll('.data-point')
      .data(points)
      .enter()
      .append('circle')
      .attr('cx', (d) => d[0])
      .attr('cy', (d) => d[1])
      .attr('r', 5)
      .style('fill', '#a78bfa')
      .style('stroke', '#8b5cf6')
      .style('stroke-width', 2)
      .on('mouseover', function () {
        d3.select(this).attr('r', 8).style('fill', '#c4b5fd');
      })
      .on('mouseout', function () {
        d3.select(this).attr('r', 5).style('fill', '#a78bfa');
      });
  }, [data]);

  return <svg ref={svgRef} style={{ width: '100%', height: 'auto' }} />;
}
