"""
Learning Velocity Chart using Plotly
Shows XP gained over time with trend analysis
"""

import React, { useEffect, useMemo } from 'react';
import Plot from 'react-plotly.js';
import { ActivityResult } from '../../../types';

interface LearningVelocityChartProps {
  data: ActivityResult[];
}

export default function LearningVelocityChart({ data }: LearningVelocityChartProps) {
  // Process data for the last 30 days
  const chartData = useMemo(() => {
    const last30Days = [...data].reverse().slice(0, 30);

    const dates = last30Days.map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (29 - i));
      return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    });

    const xpValues = last30Days.map((activity) => activity.xp_earned || 0);

    // Calculate 7-day moving average
    const movingAvg = xpValues.map((_, i) => {
      const start = Math.max(0, i - 6);
      const slice = xpValues.slice(start, i + 1);
      return slice.reduce((a, b) => a + b, 0) / slice.length;
    });

    return {
      dates,
      xpValues,
      movingAvg,
    };
  }, [data]);

  return (
    <Plot
      data={[
        {
          x: chartData.dates,
          y: chartData.xpValues,
          name: 'Daily XP',
          type: 'bar',
          marker: {
            color: '#a78bfa',
            opacity: 0.7,
          },
        },
        {
          x: chartData.dates,
          y: chartData.movingAvg,
          name: '7-Day Average',
          type: 'scatter',
          mode: 'lines',
          line: {
            color: '#ec4899',
            width: 3,
          },
        },
      ]}
