"""
Authentication routes
"""

from flask import Blueprint, request, jsonify
from flask_jwt_extended import create_access_token, jwt_required, get_jwt_identity
from app import db
from models.user import User
from models.progress import StudentProgress
from datetime import datetime

auth_bp = Blueprint('auth', __name__)

@auth_bp.route('/register', methods=['POST'])
def register():
    """Register new student"""
    data = request.get_json()

    # Validate input
    if not data or not all(k in data for k in ['username', 'email', 'password', 'age']):
        return jsonify({"error": "Missing required fields"}), 400

    # Check if user exists
    if User.query.filter_by(username=data['username']).first():
        return jsonify({"error": "Username already exists"}), 409

    if User.query.filter_by(email=data['email']).first():
        return jsonify({"error": "Email already exists"}), 409

    # Determine age group
    age = data['age']
    if age <= 9:
        age_group = 'YOUNG_EXPLORERS'
    elif age <= 13:
        age_group = 'JUNIOR_ADVENTURERS'
    elif age <= 18:
        age_group = 'TEEN_CHAMPIONS'
    else:
        age_group = 'ADULT_MASTERS'

    # Create user
    user = User(
        username=data['username'],
        email=data['email'],
        age=age,
        age_group=age_group,
        first_name=data.get('first_name', ''),
        last_name=data.get('last_name', '')
    )
    user.set_password(data['password'])

    db.session.add(user)
    db.session.flush()

    # Create progress record
    progress = StudentProgress(user_id=user.id)
    db.session.add(progress)

    db.session.commit()

    return jsonify({
        "message": "User registered successfully",
        "user": user.to_dict()
    }), 201

@auth_bp.route('/login', methods=['POST'])
def login():
    """Login student"""
    data = request.get_json()

    if not data or not data.get('username') or not data.get('password'):
        return jsonify({"error": "Missing credentials"}), 400

    user = User.query.filter_by(username=data['username']).first()

    if not user or not user.check_password(data['password']):
        return jsonify({"error": "Invalid credentials"}), 401

    # Update last played
    user.last_played = datetime.utcnow()
    db.session.commit()

    # Create JWT token
    access_token = create_access_token(identity=user.id)

    return jsonify({
        "message": "Login successful",
        "access_token": access_token,
        "user": user.to_dict()
    }), 200

@auth_bp.route('/profile', methods=['GET'])
@jwt_required()
def get_profile():
    """Get current user profile"""
    user_id = get_jwt_identity()
    user = User.query.get(user_id)

    if not user:
        return jsonify({"error": "User not found"}), 404

    progress = StudentProgress.query.filter_by(user_id=user_id).first()

    return jsonify({
        "user": user.to_dict(),
        "progress": progress.to_dict() if progress else {}
    }), 200

@auth_bp.route('/profile', methods=['PUT'])
@jwt_required()
def update_profile():
    """Update user profile"""
    user_id = get_jwt_identity()
    user = User.query.get(user_id)

    if not user:
        return jsonify({"error": "User not found"}), 404

    data = request.get_json()

    # Update allowed fields
    if 'first_name' in data:
        user.first_name = data['first_name']
    if 'last_name' in data:
        user.last_name = data['last_name']
    if 'bio' in data:
        user.bio = data['bio']
    if 'language' in data:
        user.language = data['language']

    db.session.commit()

    return jsonify({
        "message": "Profile updated",
        "user": user.to_dict()
    }), 200

@auth_bp.route('/verify', methods=['GET'])
@jwt_required()
def verify_token():
    """Verify JWT token"""
    user_id = get_jwt_identity()
    user = User.query.get(user_id)

    if not user:
        return jsonify({"error": "Invalid token"}), 401

    return jsonify({"valid": True, "user_id": user_id}), 200

