import { create } from 'zustand';
import { Activity, Progress } from '../types';
import api from '../services/api';

interface GameStore {
  activities: Activity[];
  currentActivity: Activity | null;
  progress: Progress | null;
  isLoading: boolean;

  fetchActivities: (level?: number) => Promise<void>;
  fetchActivity: (id: number) => Promise<void>;
  fetchProgress: () => Promise<void>;
  submitActivity: (activityId: number, responses: any, timeSpent: number) => Promise<any>;
}

export const useGameStore = create<GameStore>((set) => ({
  activities: [],
  currentActivity: null,
  progress: null,
  isLoading: false,

  fetchActivities: async (level?: number) => {
    set({ isLoading: true });
    try {
      const response = await api.getActivities(level);
      set({ activities: response.activities });
    } catch (error) {
      console.error('Failed to fetch activities', error);
    } finally {
      set({ isLoading: false });
    }
  },

  fetchActivity: async (id: number) => {
    set({ isLoading: true });
    try {
      const response = await api.getActivity(id);
      set({ currentActivity: response.activity });
    } catch (error) {
      console.error('Failed to fetch activity', error);
    } finally {
      set({ isLoading: false });
    }
  },

  fetchProgress: async () => {
    try {
      const response = await api.getProgressByLevel();
      set({ progress: response });
    } catch (error) {
      console.error('Failed to fetch progress', error);
    }
  },

  submitActivity: async (activityId: number, responses: any, timeSpent: number) => {
    try {
      const response = await api.submitActivity(activityId, responses, timeSpent);
      return response;
    } catch (error) {
      console.error('Failed to submit activity', error);
      throw error;
    }
  },
}));

