import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useGameStore } from '../store/gameStore';
import { useAuthStore } from '../store/authStore';
import api from '../services/api';
import { Activity } from '../types';
import { motion } from 'framer-motion';

export default function GamePage() {
  const { levelId } = useParams();
  const navigate = useNavigate();
  const [activities, setActivities] = useState<Activity[]>([]);
  const [currentActivityIndex, setCurrentActivityIndex] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [responses, setResponses] = useState<any>({});
  const [startTime, setStartTime] = useState<number>(Date.now());
  const [isSubmitting, setIsSubmitting] = useState(false);

  const user = useAuthStore((state) => state.user);

  useEffect(() => {
    const loadActivities = async () => {
      try {
        const response = await api.getActivities(parseInt(levelId!));
        setActivities(response.activities);
        setStartTime(Date.now());
      } catch (error) {
        console.error('Failed to load activities', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadActivities();
  }, [levelId]);

  const currentActivity = activities[currentActivityIndex];

  const handleResponseChange = (key: string, value: any) => {
    setResponses({
      ...responses,
      [key]: value,
    });
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      const timeSpent = Math.floor((Date.now() - startTime) / 1000);
      const result = await api.submitActivity(currentActivity.id, responses, timeSpent);

      // Show result animation
      setResponses({});

      if (currentActivityIndex < activities.length - 1) {
        setCurrentActivityIndex(currentActivityIndex + 1);
        setStartTime(Date.now());
      } else {
        // All activities completed
        navigate('/dashboard');
      }
    } catch (error) {
      console.error('Failed to submit activity', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mb-4"></div>
          <p className="text-gray-600">Loading activities...</p>
        </div>
      </div>
    );
  }

  if (!currentActivity) {
    return <div>No activities found</div>;
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-600 via-blue-500 to-cyan-400 p-4 md:p-8">
      {/* Progress Bar */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-2">
          <span className="text-white font-semibold">
            Activity {currentActivityIndex + 1} of {activities.length}
          </span>
          <span className="text-white text-sm">
            {Math.round(((currentActivityIndex + 1) / activities.length) * 100)}%
          </span>
        </div>
        <div className="w-full bg-white bg-opacity-20 rounded-full h-3">
          <motion.div
            initial={{ width: 0 }}
            animate={{
              width: `${((currentActivityIndex + 1) / activities.length) * 100}%`,
            }}
            transition={{ duration: 0.5 }}
            className="bg-white h-3 rounded-full"
          />
        </div>
      </div>

      {/* Activity Card */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-white rounded-2xl shadow-2xl p-8 max-w-2xl mx-auto"
      >
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            {currentActivity.title}
          </h1>
          <p className="text-gray-600">{currentActivity.description}</p>
        </div>

        {/* Activity Content */}
        <div className="mb-8 p-6 bg-gray-50 rounded-lg">
          {currentActivity.activity_type === 'CARD_GAME' && (
            <CardGameActivity activity={currentActivity} responses={responses} onResponseChange={handleResponseChange} />
          )}
          {currentActivity.activity_type === 'SCENARIO' && (
            <ScenarioActivity activity={currentActivity} responses={responses} onResponseChange={handleResponseChange} />
          )}
          {currentActivity.activity_type === 'DRAWING' && (
            <DrawingActivity activity={currentActivity} responses={responses} onResponseChange={handleResponseChange} />
          )}
        </div>

        {/* Navigation Buttons */}
        <div className="flex justify-between gap-4">
          <button
            onClick={() => setCurrentActivityIndex(Math.max(0, currentActivityIndex - 1))}
            disabled={currentActivityIndex === 0}
            className="px-6 py-3 bg-gray-300 text-gray-700 rounded-lg disabled:opacity-50 hover:bg-gray-400 transition-colors"
          >
            ← Previous
          </button>

          <button
            onClick={handleSubmit}
            disabled={isSubmitting}
            className="px-8 py-3 bg-gradient-to-r from-purple-600 to-blue-600 text-white rounded-lg hover:shadow-lg transition-shadow disabled:opacity-50"
          >
            {isSubmitting ? '⏳ Submitting...' : currentActivityIndex === activities.length - 1 ? '✨ Complete' : 'Next →'}
          </button>
        </div>
      </motion.div>
    </div>
  );
}

// Activity Component Variants
function CardGameActivity({ activity, responses, onResponseChange }: any) {
  const questions = activity.content?.questions || [];

  return (
    <div className="space-y-4">
      {questions.map((q: any, idx: number) => (
        <div key={idx}>
          <p className="font-semibold text-gray-900 mb-3">{q.question}</p>
          <div className="grid grid-cols-2 gap-2">
            {q.options.map((option: string, oIdx: number) => (
              <button
                key={oIdx}
                onClick={() => onResponseChange(`q${idx}`, oIdx)}
                className={`p-3 rounded-lg border-2 transition-colors ${
                  responses[`q${idx}`] === oIdx
                    ? 'border-purple-600 bg-purple-100'
                    : 'border-gray-300 hover:border-purple-300'
                }`}
              >
                {option}
              </button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

function ScenarioActivity({ activity, responses, onResponseChange }: any) {
  const scenario = activity.content?.scenario || '';
  const choices = activity.content?.choices || [];

  return (
    <div>
      <p className="text-lg font-semibold text-gray-900 mb-6">{scenario}</p>
      <div className="space-y-3">
        {choices.map((choice: any, idx: number) => (
          <button
            key={idx}
            onClick={() => onResponseChange('choice', idx)}
            className={`w-full p-4 text-left rounded-lg border-2 transition-colors ${
              responses.choice === idx
                ? 'border-purple-600 bg-purple-100'
                : 'border-gray-300 hover:border-purple-300'
            }`}
          >
            <span className="font-semibold">{choice.label}</span>
            <p className="text-sm text-gray-600 mt-1">{choice.description}</p>
          </button>
        ))}
      </div>
    </div>
  );
}

function DrawingActivity({ activity, responses, onResponseChange }: any) {
  return (
    <div className="text-center space-y-4">
      <p className="text-gray-700">{activity.content?.prompt || 'Draw your response'}</p>
      <textarea
        value={responses.drawing_response || ''}
        onChange={(e) => onResponseChange('drawing_response', e.target.value)}
        placeholder="Describe what you drew or write your response..."
        className="w-full p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
        rows={5}
      />
      <div className="flex gap-2 justify-center">
        {[1, 2, 3, 4, 5].map((level) => (
          <button
            key={level}
            onClick={() => onResponseChange('effort_level', level * 20)}
            className={`px-4 py-2 rounded-lg ${
              responses.effort_level === level * 20
                ? 'bg-purple-600 text-white'
                : 'bg-gray-200 text-gray-700'
            }`}
          >
            {'⭐'.repeat(level)}
          </button>
        ))}
      </div>
    </div>
  );
}

