"""
Activity Heatmap using D3.js
Shows activity distribution across days and weeks
"""

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import api from '../../../services/api';

interface ActivityHeatmapProps {
  userId: number;
}

export default function ActivityHeatmap({ userId }: ActivityHeatmapProps) {
  const svgRef = useRef<SVGSVGElement>(null);
  const [data, setData] = useState<any[]>([]);

  useEffect(() => {
    const loadData = async () => {
      try {
        const response = await api.getActivityHistory(365);
        const activities = response.history || [];

        // Group by date
        const dateMap: { [key: string]: number } = {};
        activities.forEach((activity: any) => {
          const date = new Date(activity.completed_at).toDateString();
          dateMap[date] = (dateMap[date] || 0) + (activity.xp_earned || 5);
        });

        // Convert to array
        const heatmapData = Object.entries(dateMap).map(([date, xp]) => ({
          date: new Date(date),
          value: xp,
        }));

        setData(heatmapData);
      } catch (error) {
        console.error('Failed to load activity data', error);
      }
    };

    loadData();
  }, [userId]);

  useEffect(() => {
    if (!svgRef.current || data.length === 0) return;

    const width = 960;
    const height = 150;
    const cellSize = 17;

    // Clear previous
    d3.select(svgRef.current).selectAll('*').remove();

    const svg = d3
      .select(svgRef.current)
      .attr('width', width)
      .attr('height', height)
      .style('background', 'transparent');

    // Group data by week
    const weekData: { [key: number]: any[] } = {};
    data.forEach((d) => {
      const week = d3.timeWeek.count(d3.timeYear(d.date), d.date);
      if (!weekData[week]) weekData[week] = [];
      weekData[week].push(d);
    });

    // Color scale
    const colorScale = d3
      .scaleLinear<string>()
      .domain([0, d3.max(data, (d) => d.value) || 100])
      .range(['#1e293b', '#a78bfa']);

    // Draw rectangles
    const weeks = Object.keys(weekData).map(Number).sort((a, b) => a - b);

    weeks.forEach((week, weekIndex) => {
      const week Data = weekData[week];

      weekData[week].forEach((d, dayIndex) => {
        const x = weekIndex * cellSize;
        const y = dayIndex * cellSize;

        svg
          .append('rect')
          .attr('x', x)
          .attr('y', y)
          .attr('width', cellSize - 2)
          .attr('height', cellSize - 2)
          .style('fill', colorScale(d.value))
          .style('stroke', '#334155')
          .style('stroke-width', 1)
          .append('title')
          .text(`${d.date.toDateString()}: ${d.value} XP`);
      });
    });

    // Add legend
    const legendX = width - 200;
    const legendY = 20;

    svg
      .append('text')
      .attr('x', legendX)
      .attr('y', legendY)
      .text('Less')
      .style('font-size', '12px')
      .style('fill', '#a1a5b4');

    for (let i = 0; i < 5; i++) {
      svg
        .append('rect')
        .attr('x', legendX + 35 + i * 18)
        .attr('y', legendY - 10)
        .attr('width', 15)
        .attr('height', 15)
        .style('fill', colorScale((i / 4) * (d3.max(data, (d) => d.value) || 100)))
        .style('stroke', '#334155');
    }

    svg
      .append('text')
      .attr('x', legendX + 130)
      .attr('y', legendY)
      .text('More')
      .style('font-size', '12px')
      .style('fill', '#a1a5b4');
  }, [data]);

  return <svg ref={svgRef} style={{ width: '100%', height: 'auto' }} />;
}

"""
Predictive Insights using Machine Learning
Forecasts future performance and recommendations
"""

import React, { useEffect, useState } from 'react';
import Plot from 'react-plotly.js';
import api from '../../../services/api';
import { motion } from 'framer-motion';

interface PredictiveInsightsProps {
  userId: number;
}

export default function PredictiveInsights({ userId }: PredictiveInsightsProps) {
  const [prediction, setPrediction] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadPrediction = async () => {
      try {
        const response = await api.getInsights();
        setPrediction(response);
      } catch (error) {
        console.error('Failed to load predictions', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadPrediction();
  }, [userId]);

  if (isLoading) {
    return <div className="text-white">Loading predictions...</div>;
  }

  // Generate forecast data (30 days ahead)
  const currentXp = prediction?.metrics?.xp_for_next_level || 150;
  const forecastData = Array.from({ length: 30 }, (_, i) => ({
    day: i,
    predicted: currentXp + (i * Math.random() * 10) + (i * 3), // Trend + variance
  }));

  return (
    <div className="space-y-6">
      {/* Forecast Chart */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-slate-800/30 rounded-lg p-4"
      >
