"""
Engagement Metrics Dashboard
Shows user activity patterns and engagement trends
"""

import React from 'react';
import { motion } from 'framer-motion';

interface EngagementMetricsProps {
  stats: {
    total_xp: number;
    level: number;
    title: string;
    streak_days: number;
    total_activities: number;
    average_accuracy: number;
    average_score: number;
  };
}

export default function EngagementMetrics({ stats }: EngagementMetricsProps) {
  const metrics = [
    {
      label: 'Activity Completion Rate',
      value: `${Math.min(100, (stats.total_activities / 50) * 100).toFixed(1)}%`,
      icon: '📊',
      color: 'from-purple-500 to-purple-600',
    },
    {
      label: 'Consistency Score',
      value: `${Math.min(100, stats.streak_days * 5)}%`,
      icon: '🔥',
      color: 'from-red-500 to-orange-500',
    },
    {
      label: 'Learning Efficiency',
      value: `${(stats.average_accuracy * 0.8).toFixed(1)}%`,
      icon: '⚡',
      color: 'from-yellow-500 to-amber-500',
