"""
Peer Comparison Chart
Compare your progress with similar users
"""

import React, { useEffect, useState } from 'react';
import Plot from 'react-plotly.js';
import api from '../../../services/api';

interface PeerComparisonProps {
  userId: number;
}

export default function PeerComparison({ userId }: PeerComparisonProps) {
  const [comparisonData, setComparisonData] = useState<any>(null);

  useEffect(() => {
    const loadComparison = async () => {
      try {
        const response = await api.getLeaderboard(10);
        setComparisonData(response.leaderboard);
      } catch (error) {
        console.error('Failed to load comparison', error);
      }
    };

    loadComparison();
  }, [userId]);

  if (!comparisonData) return <div className="text-white">Loading...</div>;

  return (
    <Plot
      data={[
        {
          x: comparisonData.map((u: any) => u.username),
          y: comparisonData.map((u: any) => u.xp),
          name: 'XP',
          type: 'bar',
          marker: {
            color: comparisonData.map((u: any, idx: number) =>
              idx === 0 ? '#fbbf24' : idx === 1 ? '#c0c0c0' : idx === 2 ? '#cd7f32' : '#a78bfa'
            ),
          },
        },
      ]}
      layout={{
        title: 'Top Players Comparison',
        height: 400,
        plot_bgcolor: 'rgba(15, 23, 42, 0)',
        paper_bgcolor: 'rgba(15, 23, 42, 0)',
        font: { color: '#e2e8f0' },
        xaxis: { showgrid: false },
        yaxis: {
          showgrid: true,
          gridcolor: 'rgba(148, 163, 184, 0.1)',
        },
        margin: { l: 50, r: 20, t: 50, b: 80 },
      }}
      style={{ width: '100%' }}
    />
  );
}

