"""
Advanced Analytics Service
Real-time metric calculation and visualization data generation
"""

import numpy as np
from datetime import datetime, timedelta
from sqlalchemy import func
from app import db
from models.activity import ActivityProgress, Activity
from models.user import User
from models.progress import StudentProgress
import json

class AdvancedAnalyticsService:
    """Generate comprehensive analytics data"""

    @staticmethod
    def generate_heatmap_data(user_id: int) -> dict:
        """Generate activity heatmap data"""

        # Get last 365 days of activity
        one_year_ago = datetime.utcnow() - timedelta(days=365)

        activities = ActivityProgress.query.filter(
            ActivityProgress.user_id == user_id,
            ActivityProgress.completed_at >= one_year_ago
        ).all()

        # Group by date
        date_map = {}
        for activity in activities:
            date_key = activity.completed_at.strftime('%Y-%m-%d')
            date_map[date_key] = date_map.get(date_key, 0) + (activity.xp_earned or 5)

        return {
            'dates': list(date_map.keys()),
            'xp_values': list(date_map.values()),
            'total_days_active': len(date_map)
        }

    @staticmethod
    def calculate_engagement_score(user_id: int) -> float:
        """Calculate comprehensive engagement score (0-100)"""

        user = User.query.get(user_id)
        activities = ActivityProgress.query.filter_by(user_id=user_id).all()

        if not activities:
            return 0

        # Activity frequency (0-30 points)
        days_active = len(set(a.completed_at.date() for a in activities))
        frequency_score = min(30, (days_active / 30) * 30)

        # Consistency - recent activity (0-20 points)
        if user.last_played:
            days_since_last = (datetime.utcnow() - user.last_played).days
            consistency_score = max(0, 20 - (days_since_last * 2))
        else:
            consistency_score = 0

        # Performance quality (0-30 points)
        avg_accuracy = np.mean([a.accuracy for a in activities[-10:]])
        performance_score = (avg_accuracy / 100) * 30

        # Variety - different activity types (0-20 points)
        unique_types = len(set(a.activity.activity_type for a in activities if a.activity))
        variety_score = (unique_types / 7) * 20  # Assume 7 activity types

        return min(100, frequency_score + consistency_score + performance_score + variety_score)

    @staticmethod
    def forecast_xp(user_id: int, days_ahead: int = 30) -> list:
        """Forecast XP progression"""

        activities = ActivityProgress.query.filter_by(user_id=user_id).order_by(
            ActivityProgress.completed_at.desc()
        ).limit(30).all()

        if not activities:
            return [0] * days_ahead

        # Calculate average daily XP
        recent_xp = [a.xp_earned or 5 for a in activities[-7:]]
        avg_daily_xp = np.mean(recent_xp)

        # Generate forecast with trend
        forecast = []
        current_xp = recent_xp[-1] if recent_xp else 0

        for day in range(days_ahead):
            # Add random variance and slight upward trend
            trend = (day / days_ahead) * (avg_daily_xp * 0.1)
            variance = np.random.normal(0, avg_daily_xp * 0.2)
            predicted_xp = current_xp + avg_daily_xp + trend + variance
            forecast.append(max(0, int(predicted_xp)))
            current_xp = predicted_xp

        return forecast

    @staticmethod
    def calculate_skill_projection(user_id: int) -> dict:
        """Project skill progression"""

        progress = StudentProgress.query.filter_by(user_id=user_id).first()

        if not progress:
            return {}

        skills = {
            'self_awareness': progress.level1_awareness_xp,
            'communication': progress.level2_communication_xp,
            'decision_making': progress.level3_decision_xp,
            'creativity': progress.level4_creativity_xp,
            'wellness': progress.level5_wellness_xp
        }

        # Calculate growth rates
        user = User.query.get(user_id)
        total_days = max(1, (datetime.utcnow() - user.created_at).days)

        projections = {}
        for skill, xp in skills.items():
            daily_rate = xp / total_days if total_days > 0 else 0
            projected_xp_90_days = xp + (daily_rate * 90)

            projections[skill] = {
                'current': xp,
                'daily_rate': round(daily_rate, 2),
                'projected_90_days': round(projected_xp_90_days, 0)
            }

        return projections

    @staticmethod
    def get_performance_distribution(user_id: int) -> dict:
        """Get distribution of performance metrics"""

        activities = ActivityProgress.query.filter_by(user_id=user_id).all()

        if not activities:
            return {
                'accuracy_distribution': [],
                'score_distribution': [],
                'time_distribution': []
            }

        accuracies = [a.accuracy for a in activities]
        scores = [a.score for a in activities]
        times = [a.time_spent_seconds for a in activities]

        return {
            'accuracy_distribution': {
                'min': float(np.min(accuracies)),
                'max': float(np.max(accuracies)),
                'mean': float(np.mean(accuracies)),
                'std': float(np.std(accuracies)),
                'percentile_25': float(np.percentile(accuracies, 25)),
                'percentile_75': float(np.percentile(accuracies, 75))
            },
            'score_distribution': {
                'min': float(np.min(scores)),
                'max': float(np.max(scores)),
                'mean': float(np.mean(scores)),
                'std': float(np.std(scores))
            },
            'time_distribution': {
                'min': float(np.min(times)),
                'max': float(np.max(times)),
                'mean': float(np.mean(times)),
                'median': float(np.median(times))
            }
        }

    @staticmethod
    def identify_learning_patterns(user_id: int) -> dict:
        """Identify learning patterns"""

        activities = ActivityProgress.query.filter_by(user_id=user_id).order_by(
            ActivityProgress.completed_at
        ).all()

        if not activities:
            return {}

        # Time of day analysis
        hours = [a.completed_at.hour for a in activities]
        hour_distribution = {}
        for hour in hours:
            hour_distribution[hour] = hour_distribution.get(hour, 0) + 1

        peak_hour = max(hour_distribution, key=hour_distribution.get)

        # Day of week analysis
        days = [a.completed_at.strftime('%A') for a in activities]
        day_distribution = {}
        for day in days:
            day_distribution[day] = day_distribution.get(day, 0) + 1

        favorite_day = max(day_distribution, key=day_distribution.get)

        # Session length analysis
        session_lengths = []
        current_session_start = activities[0].completed_at
        session_xp = 0

        for activity in activities:
            time_since_last = (activity.completed_at - current_session_start).total_seconds()

            if time_since_last > 3600:  # More than 1 hour = new session
                session_lengths.append(session_xp)
                current_session_start = activity.completed_at
                session_xp = 0

            session_xp += activity.xp_earned or 5

        return {
            'peak_hour': peak_hour,
            'favorite_day': favorite_day,
            'hour_distribution': hour_distribution,
            'day_distribution': day_distribution,
            'average_session_xp': round(np.mean(session_lengths) if session_lengths else 0, 2),
            'sessions_count': len(session_lengths)
        }

    @staticmethod
    def generate_comprehensive_report(user_id: int) -> dict:
        """Generate complete analytics report"""

        user = User.query.get(user_id)
        progress = StudentProgress.query.
